<!DOCTYPE html>
<html lang="fr" data-theme="dark">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>USTHB — Gestion de la Scolarité</title>
<link rel="preconnect" href="https://fonts.googleapis.com">
<link href="https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,600;0,700;1,600;1,700&family=Manrope:wght@300;400;500;600;700;800&family=JetBrains+Mono:wght@400;500&display=swap" rel="stylesheet">
<style>
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
html{scroll-behavior:smooth}
body{font-family:"Manrope",sans-serif;overflow-x:hidden;transition:background .4s,color .4s}
a{text-decoration:none;color:inherit}
img{display:block}

/* ══════════════════════════════
   THEME TOKENS
══════════════════════════════ */
[data-theme="dark"]{
  --bg:      #070B14;
  --bg2:     #0D1220;
  --bg3:     #121828;
  --bg4:     #161E2E;
  --border:  rgba(255,255,255,0.06);
  --b2:      rgba(255,255,255,0.10);
  --b3:      rgba(255,255,255,0.16);
  --text:    #E8EAF0;
  --sub:     #3D4A5C;
  --sub2:    #7A8899;
  --sub3:    #A8B8C8;
  --heading: #FFFFFF;
  --card-bg: #0D1220;
  --card-bg2:#121828;
  --nav-bg:  rgba(7,11,20,.92);
  --shadow:  0 20px 50px rgba(0,0,0,.4);
  --em:      #3451B5;
  --em2:     #2740A0;
  --em3:     #5B7FE0;
  --sky:     #4B9EFF;
  --amber:   #F59E0B;
  --rose:    #FF4D6A;
  --logo-filter: brightness(5);
  --glow1: rgba(52,81,181,.12);
  --glow2: rgba(91,127,224,.08);
  --glow3: rgba(52,81,181,.06);
}

[data-theme="light"]{
  --bg:       #F0F3FA;
  --bg2:      #FFFFFF;
  --bg3:      #E8EDF8;
  --bg4:      #E0E8F5;
  --border:   rgba(0,0,0,0.07);
  --b2:       rgba(0,0,0,0.11);
  --b3:       rgba(0,0,0,0.16);
  --text:     #1A1E2E;
  --sub:      #BCC4D8;
  --sub2:     #6B74A0;
  --sub3:     #3A4068;
  --heading:  #0F1230;
  --card-bg:  #FFFFFF;
  --card-bg2: #F0F3FA;
  --nav-bg:   rgba(240,243,250,.94);
  --em:       #2740A0;
  --em2:      #1C318A;
  --em3:      #3451B5;
  --sky:      #2277DD;
  --amber:    #D4860A;
  --rose:     #E03050;
  --green:    #059669;
  --red:      #DC2626;
  --logo-filter: brightness(1);
  --shadow:   0 20px 60px rgba(52,81,181,.08);
  --glow1: rgba(52,81,181,.07);
  --glow2: rgba(91,127,224,.05);
  --glow3: rgba(52,81,181,.04);
}

body{background:var(--bg);color:var(--text)}

/* ══ THEME TOGGLE ══ */
.theme-toggle {
  position: fixed; bottom: 24px; right: 24px; z-index: 200;
  width: 46px; height: 46px; border-radius: 12px;
  background: var(--card-bg); border: 1px solid var(--b2);
  display: grid; place-items: center; cursor: pointer; font-size: 20px;
  box-shadow: 0 4px 20px rgba(0,0,0,.2);
  transition: transform .2s, box-shadow .2s, background .3s;
}
.theme-toggle:hover { transform: scale(1.1); box-shadow: 0 6px 28px rgba(0,0,0,.3); }
.icon-sun  { display: none; }
.icon-moon { display: block; }
[data-theme="light"] .icon-sun  { display: block; }
[data-theme="light"] .icon-moon { display: none; }

/* ══════════════════════════════
   NAV
══════════════════════════════ */
nav{
  position:fixed;inset-block-start:0;inset-inline:0;z-index:100;
  height:70px;
  display:flex;align-items:center;justify-content:space-between;
  padding:0 clamp(20px,4vw,64px);
  border-bottom:1px solid transparent;
  transition:background .4s,border-color .4s;
}
nav.scrolled{
  background:var(--nav-bg);
  backdrop-filter:blur(20px);
  -webkit-backdrop-filter:blur(20px);
  border-color:var(--border);
}
.nb{display:flex;align-items:center;gap:12px}
.nb img{height:42px;width:42px;object-fit:contain;filter:var(--logo-filter)}
.nb-t b{display:block;font-weight:700;font-size:14px;color:var(--heading);letter-spacing:.04em}
.nb-t small{font-size:10px;color:var(--sub2);letter-spacing:.08em;text-transform:uppercase}
.nl{display:flex;gap:36px;list-style:none}
.nl a{
  font-size:13px;font-weight:500;color:var(--sub3);
  position:relative;padding-bottom:3px;transition:color .2s;
}
.nl a::after{
  content:"";position:absolute;bottom:0;left:0;
  width:0;height:1.5px;background:var(--em);border-radius:1px;
  transition:width .25s;
}
.nl a:hover{color:var(--heading)}
.nl a:hover::after{width:100%}
.nav-right{display:flex;align-items:center;gap:10px}
.ncta{
  display:flex;align-items:center;gap:8px;
  padding:9px 22px;
  background:transparent;
  border:1px solid rgba(52,81,181,.35);
  border-radius:8px;
  font-family:"Manrope",sans-serif;font-size:13px;font-weight:600;
  color:var(--em);cursor:pointer;
  transition:background .2s,border-color .2s,box-shadow .2s;
}
.ncta:hover{
  background:rgba(52,81,181,.08);
  border-color:var(--em);
  box-shadow:0 0 20px rgba(52,81,181,.15);
}

/* ══════════════════════════════
   HERO
══════════════════════════════ */
.hero{
  min-height:100vh;
  padding-top:70px;
  display:flex;align-items:center;
  position:relative;overflow:hidden;
  background:var(--bg);
}
.glow{position:absolute;border-radius:50%;pointer-events:none;filter:blur(90px)}
.g1{width:700px;height:700px;background:var(--glow1);top:-150px;left:-100px;animation:drift1 14s ease-in-out infinite}
.g2{width:500px;height:500px;background:var(--glow2);top:10%;right:-60px;animation:drift2 18s ease-in-out infinite}
.g3{width:350px;height:350px;background:var(--glow3);bottom:-80px;left:40%;animation:drift3 12s ease-in-out infinite}
.hero-grid{
  position:absolute;inset:0;pointer-events:none;
  background-image:radial-gradient(circle,var(--border) 1px,transparent 1px);
  background-size:32px 32px;
  mask-image:radial-gradient(ellipse 80% 70% at 50% 50%,black 40%,transparent 100%);
}
.hero-inner{
  position:relative;z-index:2;
  width:100%;max-width:1300px;margin:0 auto;
  padding:clamp(56px,8vh,100px) clamp(24px,5vw,72px);
  display:grid;grid-template-columns:1fr 1fr;
  gap:clamp(40px,5vw,80px);align-items:center;
}
.hl{}
.hl-badge{
  display:inline-flex;align-items:center;gap:8px;
  padding:5px 16px 5px 5px;
  background:rgba(52,81,181,.07);
  border:1px solid rgba(52,81,181,.20);
  border-radius:100px;margin-bottom:clamp(22px,3.5vh,38px);
  width:fit-content;
  opacity:0;transform:translateY(10px);animation:fup .5s .1s forwards;
}
.hl-badge-dot{
  width:24px;height:24px;border-radius:50%;
  background:linear-gradient(135deg,var(--em),var(--em3));
  display:grid;place-items:center;font-size:11px;flex-shrink:0;
}
.hl-badge span{font-family:"JetBrains Mono",monospace;font-size:10.5px;color:var(--em);letter-spacing:.09em;text-transform:uppercase}
.hl-title{
  font-family:"Cormorant Garamond",Georgia,serif;
  font-size:clamp(52px,6.8vw,96px);
  font-weight:700;line-height:.92;letter-spacing:-.01em;
  color:var(--heading);margin-bottom:clamp(18px,3vh,30px);
}
.hl-title .ln{display:block;overflow:hidden}
.hl-title .ln span{display:block;opacity:0;transform:translateY(108%)}
.hl-title .ln:nth-child(1) span{animation:sup .7s .25s forwards}
.hl-title .ln:nth-child(2) span{animation:sup .7s .40s forwards}
.hl-title .ln:nth-child(3) span{
  animation:sup .7s .55s forwards;font-style:italic;
  background:linear-gradient(90deg,var(--em),var(--em3),#7B9EFF);
  -webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;
}
.hl-sub{
  font-size:clamp(14px,1.5vw,16.5px);line-height:1.75;
  color:var(--sub3);max-width:440px;
  margin-bottom:clamp(28px,4.5vh,48px);
  opacity:0;animation:fup .6s .75s forwards;
}
.hl-sub strong{color:var(--text);font-weight:600}
.hl-btns{
  display:flex;gap:12px;flex-wrap:wrap;
  margin-bottom:clamp(32px,5vh,52px);
  opacity:0;animation:fup .6s .9s forwards;
}
.btn-main{
  padding:13px 28px;background:var(--em);color:#fff;
  font-family:"Manrope",sans-serif;font-size:14px;font-weight:700;
  border:none;border-radius:14px;cursor:pointer;
  box-shadow:0 6px 28px rgba(52,81,181,.28);
  transition:background .2s,transform .15s,box-shadow .2s;
}
.btn-main:hover{background:var(--em2);transform:translateY(-2px);box-shadow:0 10px 36px rgba(52,81,181,.38)}
.btn-sec{
  padding:13px 28px;background:transparent;color:var(--sub3);
  font-family:"Manrope",sans-serif;font-size:14px;font-weight:600;
  border:1px solid var(--b2);border-radius:14px;cursor:pointer;
  transition:border-color .2s,color .2s,background .2s;
}
.btn-sec:hover{border-color:var(--b3);color:var(--heading);background:rgba(0,0,0,.04)}
.hl-pills{
  display:flex;gap:10px;flex-wrap:wrap;
  opacity:0;animation:fup .6s 1.1s forwards;
}
.pill{
  display:flex;align-items:center;gap:8px;
  padding:8px 14px;background:var(--card-bg);
  border:1px solid var(--border);border-radius:100px;
}
.pill-dot{width:7px;height:7px;border-radius:50%;flex-shrink:0}
.pill span{font-size:13px;font-weight:600;color:var(--heading)}
.pill small{font-size:11px;color:var(--sub2)}

/* RIGHT — access panel */
.hr{opacity:0;animation:fup .7s .5s forwards}
.access-panel{
  background:var(--card-bg);border:1px solid var(--b2);
  border-radius:20px;overflow:hidden;position:relative;
  max-width:420px;width:100%;margin:0 auto;
  box-shadow:var(--shadow);
}
.access-panel::before{
  content:"";position:absolute;top:0;left:0;right:0;height:2px;
  background:linear-gradient(90deg,var(--em),var(--em3),#7B9EFF);
}
.ap-head{
  display:flex;align-items:center;gap:14px;
  padding:22px 24px 18px;border-bottom:1px solid var(--border);
}
.ap-head-ico{
  width:46px;height:46px;border-radius:12px;
  background:var(--card-bg2);border:1px solid var(--border);
  display:grid;place-items:center;flex-shrink:0;
}
.ap-head-ico img{height:28px;width:28px;object-fit:contain;filter:var(--logo-filter)}
.ap-head-title{font-size:15px;font-weight:700;color:var(--heading);display:block;margin-bottom:2px}
.ap-head-sub{font-size:12px;color:var(--sub2)}
.ap-roles{padding:16px;display:flex;flex-direction:column;gap:10px}
.ap-role{
  display:flex;align-items:center;justify-content:space-between;
  padding:16px 18px;border-radius:12px;
  border:1.5px solid var(--border);background:var(--card-bg2);
  transition:transform .2s,border-color .25s,background .25s,box-shadow .2s;
}
.ap-role:hover{transform:translateX(5px)}
.ap-s:hover{border-color:rgba(52,81,181,.35);background:rgba(0,200,150,.05);box-shadow:4px 0 0 var(--em)}
.ap-t:hover{border-color:rgba(245,158,11,.35);background:rgba(245,158,11,.05);box-shadow:4px 0 0 var(--amber)}
.ap-a:hover{border-color:rgba(255,77,106,.35);background:rgba(255,77,106,.05);box-shadow:4px 0 0 var(--rose)}
.apr-l{display:flex;align-items:center;gap:14px}
.apr-ico{
  width:44px;height:44px;border-radius:12px;
  display:grid;place-items:center;font-size:20px;flex-shrink:0;transition:transform .2s;
}
.ap-s .apr-ico{background:rgba(0,200,150,.1)}
.ap-t .apr-ico{background:rgba(245,158,11,.08)}
.ap-a .apr-ico{background:rgba(255,77,106,.08)}
.ap-role:hover .apr-ico{transform:scale(1.1)}
.apr-name{font-size:14px;font-weight:700;color:var(--heading);display:block;margin-bottom:2px}
.apr-desc{font-size:12px;color:var(--sub2)}
.apr-arr{font-family:"JetBrains Mono",monospace;font-size:16px;color:var(--sub);transition:transform .2s,color .2s}
.ap-s:hover .apr-arr{color:var(--em);transform:translateX(3px)}
.ap-t:hover .apr-arr{color:var(--amber);transform:translateX(3px)}
.ap-a:hover .apr-arr{color:var(--rose);transform:translateX(3px)}
.ap-foot{
  display:flex;align-items:center;justify-content:space-between;
  padding:14px 24px;border-top:1px solid var(--border);
  background:rgba(52,81,181,.04);
}
.ap-session{display:flex;align-items:center;gap:8px;font-family:"JetBrains Mono",monospace;font-size:11px;color:var(--sub2)}
.ap-dot{
  width:7px;height:7px;border-radius:50%;background:var(--em);flex-shrink:0;
  box-shadow:0 0 0 3px rgba(52,81,181,.2);animation:blink 1.8s ease-in-out infinite;
}
.ap-login{font-family:"JetBrains Mono",monospace;font-size:12px;color:var(--em);transition:color .2s}
.ap-login:hover{color:var(--em3)}

/* ══════════════════════════════
   STATS
══════════════════════════════ */
.stats{
  background:var(--bg2);
  border-top:1px solid var(--border);border-bottom:1px solid var(--border);
  padding:clamp(52px,7vh,88px) clamp(24px,5vw,72px);
}
.stats-inner{
  max-width:1300px;margin:0 auto;
  display:grid;grid-template-columns:repeat(4,1fr);
  gap:1px;background:var(--border);border-radius:16px;overflow:hidden;
}
.st{
  background:var(--bg2);
  padding:clamp(26px,4vh,42px) clamp(22px,3vw,36px);
  position:relative;transition:background .2s;
}
.st:hover{background:var(--bg3)}
.st::after{
  content:"";position:absolute;top:0;left:0;
  width:2px;height:0;transition:height .45s ease;
}
.st:nth-child(1)::after{background:var(--em)}
.st:nth-child(2)::after{background:var(--sky)}
.st:nth-child(3)::after{background:var(--amber)}
.st:nth-child(4)::after{background:var(--rose)}
.st:hover::after{height:100%}
.st-n{
  font-family:"Cormorant Garamond",Georgia,serif;
  font-size:clamp(40px,4.8vw,62px);font-weight:700;line-height:1;
  display:block;margin-bottom:10px;
}
.st:nth-child(1) .st-n{color:var(--em)}
.st:nth-child(2) .st-n{color:var(--sky)}
.st:nth-child(3) .st-n{color:var(--amber)}
.st:nth-child(4) .st-n{color:var(--rose)}
.st-l{font-size:11.5px;color:var(--sub2);letter-spacing:.07em;text-transform:uppercase;display:block}
.st-d{font-size:13px;color:var(--sub3);margin-top:6px;line-height:1.5}

/* ══════════════════════════════
   FEATURES
══════════════════════════════ */
.features{
  padding:clamp(64px,9vh,110px) clamp(24px,5vw,72px);
  background:var(--bg);
}
.fw{max-width:1300px;margin:0 auto}
.sk{
  display:inline-flex;align-items:center;gap:8px;
  font-family:"JetBrains Mono",monospace;font-size:11px;color:var(--em);
  letter-spacing:.12em;text-transform:uppercase;margin-bottom:12px;
}
.sk::before{content:"";width:20px;height:1.5px;background:var(--em);border-radius:1px}
.sh2{
  font-family:"Cormorant Garamond",Georgia,serif;
  font-size:clamp(32px,4vw,54px);font-weight:700;
  line-height:1.0;letter-spacing:-.01em;margin-bottom:10px;color:var(--heading);
}
.sp{font-size:15px;color:var(--sub3);line-height:1.75;max-width:480px;margin-bottom:clamp(40px,6vh,72px)}
.feat-layout{display:flex;flex-direction:column;gap:16px}
.feat-top{display:grid;grid-template-columns:1fr 1fr;gap:16px}
.feat-bot{display:grid;grid-template-columns:repeat(4,1fr);gap:16px}
.fc{
  background:var(--card-bg);border:1px solid var(--border);
  border-radius:14px;padding:clamp(24px,3.5vh,38px) clamp(20px,2.5vw,32px);
  position:relative;overflow:hidden;
  transition:border-color .25s,background .25s,transform .25s,box-shadow .25s;
}
.fc:hover{border-color:var(--b2);background:var(--card-bg2);transform:translateY(-3px);box-shadow:var(--shadow)}
.fc::after{
  content:"";position:absolute;bottom:0;left:0;
  width:0;height:2px;background:linear-gradient(90deg,var(--em),var(--em3));
  transition:width .4s ease;
}
.fc:hover::after{width:100%}
.fc-num{font-family:"JetBrains Mono",monospace;font-size:10.5px;color:var(--sub);letter-spacing:.06em;display:block;margin-bottom:14px}
.fc-ico{
  width:48px;height:48px;border-radius:12px;
  background:var(--card-bg2);border:1px solid var(--border);
  display:grid;place-items:center;font-size:22px;
  margin-bottom:18px;transition:transform .25s,border-color .25s;
}
.fc:hover .fc-ico{transform:scale(1.1) rotate(-5deg);border-color:rgba(52,81,181,.22)}
.fc-title{font-weight:700;font-size:15.5px;color:var(--heading);margin-bottom:8px}
.fc-desc{font-size:13.5px;color:var(--sub3);line-height:1.65}
.fc-small .fc-ico{width:40px;height:40px;font-size:18px;margin-bottom:14px}
.fc-small .fc-title{font-size:14.5px}
.fc-small .fc-desc{font-size:13px}

/* ══════════════════════════════
   ACCESS SECTION
══════════════════════════════ */
.access-sec{
  padding:clamp(64px,9vh,110px) clamp(24px,5vw,72px);
  background:var(--bg2);border-top:1px solid var(--border);
}
.ac-grid{
  display:grid;grid-template-columns:repeat(3,1fr);
  gap:16px;margin-top:clamp(36px,5vh,60px);
}
.ac{
  background:var(--card-bg);border:1px solid var(--border);
  border-radius:18px;padding:clamp(28px,4vh,44px) clamp(22px,2.5vw,32px);
  display:flex;flex-direction:column;position:relative;overflow:hidden;
  transition:transform .3s,border-color .3s,box-shadow .3s;
}
.ac::before{
  content:"";position:absolute;top:0;left:0;right:0;height:2px;
  transform:scaleX(0);transform-origin:left;transition:transform .4s ease;
}
.ac-1::before{background:linear-gradient(90deg,var(--em),var(--em3))}
.ac-2::before{background:linear-gradient(90deg,var(--amber),#FFD580)}
.ac-3::before{background:linear-gradient(90deg,var(--rose),#FF9EAD)}
.ac:hover{transform:translateY(-6px)}
.ac-1:hover{border-color:rgba(52,81,181,.22);box-shadow:0 20px 50px rgba(52,81,181,.07)}
.ac-2:hover{border-color:rgba(245,158,11,.25);box-shadow:0 20px 50px rgba(245,158,11,.07)}
.ac-3:hover{border-color:rgba(255,77,106,.25);box-shadow:0 20px 50px rgba(255,77,106,.07)}
.ac:hover::before{transform:scaleX(1)}
.ac-tag{
  display:inline-flex;align-items:center;gap:6px;
  padding:4px 12px;border-radius:6px;
  font-family:"JetBrains Mono",monospace;font-size:9.5px;letter-spacing:.1em;text-transform:uppercase;
  margin-bottom:clamp(18px,3vh,28px);align-self:flex-start;
}
.ac-1 .ac-tag{background:rgba(52,81,181,.08);color:var(--em);border:1px solid rgba(52,81,181,.20)}
.ac-2 .ac-tag{background:rgba(245,158,11,.08);color:var(--amber);border:1px solid rgba(245,158,11,.18)}
.ac-3 .ac-tag{background:rgba(255,77,106,.08);color:var(--rose);border:1px solid rgba(255,77,106,.18)}
.ac-ico{font-size:34px;display:block;margin-bottom:18px;transition:transform .3s}
.ac:hover .ac-ico{transform:scale(1.1)}
.ac-title{
  font-family:"Cormorant Garamond",Georgia,serif;
  font-size:clamp(22px,2.3vw,30px);font-weight:700;
  letter-spacing:-.01em;line-height:1.1;color:var(--heading);margin-bottom:10px;
}
.ac-desc{font-size:13.5px;color:var(--sub3);line-height:1.65;flex:1;margin-bottom:22px}
.ac-link{display:inline-flex;align-items:center;gap:8px;font-size:13px;font-weight:700;transition:gap .2s}
.ac-1 .ac-link{color:var(--em)}
.ac-2 .ac-link{color:var(--amber)}
.ac-3 .ac-link{color:var(--rose)}
.ac:hover .ac-link{gap:14px}

/* ══════════════════════════════
   FOOTER
══════════════════════════════ */
footer{
  background:var(--bg2);border-top:1px solid var(--border);
  padding:clamp(48px,6vh,72px) clamp(24px,5vw,72px) clamp(24px,3vh,36px);
}
.fg{
  max-width:1300px;margin:0 auto;
  display:grid;grid-template-columns:1.6fr 1fr 1fr 1fr;
  gap:40px;padding-bottom:clamp(32px,4vh,44px);
  border-bottom:1px solid var(--border);margin-bottom:clamp(20px,3vh,28px);
}
.fb-r{display:flex;align-items:center;gap:12px;margin-bottom:14px}
.fb-r img{height:40px;width:40px;object-fit:contain;filter:var(--logo-filter)}
.fb-r b{font-weight:700;font-size:14px;color:var(--heading);letter-spacing:.04em}
.fb-r small{display:block;font-size:9.5px;color:var(--sub2);letter-spacing:.08em;text-transform:uppercase}
.fb-p{font-size:13px;color:var(--sub2);line-height:1.7;max-width:240px}
.fc-h h5{font-size:10.5px;font-weight:600;letter-spacing:.12em;text-transform:uppercase;color:var(--sub3);margin-bottom:16px}
.fc-h ul{list-style:none}
.fc-h ul li{margin-bottom:9px}
.fc-h ul li a{font-size:13px;color:var(--sub2);transition:color .2s}
.fc-h ul li a:hover{color:var(--em)}
.fbot{
  max-width:1300px;margin:0 auto;
  display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:10px;
}
.fbot p{font-size:12px;color:var(--sub2)}
.fbot code{font-family:"JetBrains Mono",monospace;font-size:11px;color:var(--sub)}

/* ══════════════════════════════
   ANIMATIONS
══════════════════════════════ */
@keyframes fup{to{opacity:1;transform:translateY(0)}}
@keyframes sup{to{opacity:1;transform:translateY(0)}}
@keyframes blink{0%,100%{opacity:1}50%{opacity:.3}}
@keyframes drift1{0%,100%{transform:translate(0,0)}50%{transform:translate(35px,25px)}}
@keyframes drift2{0%,100%{transform:translate(0,0)}50%{transform:translate(-28px,35px)}}
@keyframes drift3{0%,100%{transform:translate(0,0)}50%{transform:translate(18px,-22px)}}

.rev{opacity:0;transform:translateY(22px);transition:opacity .6s ease,transform .6s ease}
.rev.on{opacity:1;transform:none}
.d1{transition-delay:.08s}.d2{transition-delay:.16s}.d3{transition-delay:.24s}
.d4{transition-delay:.32s}.d5{transition-delay:.40s}.d6{transition-delay:.48s}

/* ══════════════════════════════
   RESPONSIVE
══════════════════════════════ */
@media(max-width:1100px){
  .hero-inner{grid-template-columns:1fr}
  .hr{display:none}
  .stats-inner{grid-template-columns:repeat(2,1fr)}
  .feat-bot{grid-template-columns:repeat(2,1fr)}
  .ac-grid{grid-template-columns:repeat(2,1fr)}
  .fg{grid-template-columns:1fr 1fr;gap:28px}
  .nl{display:none}
  nav{padding:0 24px}
}
@media(max-width:640px){
