<!-- Theme Toggle -->
 <button class="theme-toggle" id="themeToggle" title="Changer le thème">
      <span class="icon-moon">🌙</span>
      <span class="icon-sun">☀️</span>
    </button>
<script>
// Theme
const html = document.documentElement;
const btn  = document.getElementById('themeToggle');
const saved = localStorage.getItem('usthb-theme') || 'dark';
html.setAttribute('data-theme', saved);

btn.addEventListener('click', () => {
  const next = html.getAttribute('data-theme') === 'dark' ? 'light' : 'dark';
  html.setAttribute('data-theme', next);
  localStorage.setItem('usthb-theme', next);
});

// Nav scroll
const nav = document.getElementById('nav');
window.addEventListener('scroll', () => nav.classList.toggle('scrolled', scrollY > 50));

// Scroll reveal
const ro = new IntersectionObserver(es => es.forEach(e => { if(e.isIntersecting) e.target.classList.add('on'); }), {threshold:0.1});
document.querySelectorAll('.rev').forEach(el => ro.observe(el));

// Counters
function count(el, target, dur=1600){
  let s=null;
  const run=ts=>{ if(!s)s=ts; const p=Math.min((ts-s)/dur,1); el.textContent=Math.floor((1-Math.pow(1-p,3))*target); if(p<1)requestAnimationFrame(run); else el.textContent=target; };
  requestAnimationFrame(run);
}
const co = new IntersectionObserver(es=>es.forEach(e=>{ if(e.isIntersecting){count(e.target,+e.target.dataset.target);co.unobserve(e.target);} }),{threshold:0.5});
document.querySelectorAll('.cnt').forEach(el=>co.observe(el));
</script>
